text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표",
        "decision": "스모크 테스트가 통과하면 공개 릴리스 목표는 금요일 15:00 KST로 한다."
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수요일 공개 릴리스",
        "result": "거절됨",
        "reason": "스모크 테스트 통과가 선행되어야 한다."
      },
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경",
        "result": "거절됨",
        "reason": "우선 패키지 설정과 계약 적합성을 확인하는 절차를 따르기로 했다."
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 릴리스",
        "status": "내부 스트레치 목표",
        "note": "최종 결정은 아니며, 공개 목표는 금요일 15:00 KST이다."
      },
      {
        "item": "README 설치 단계 검토",
        "status": "가능하면 목요일까지 검토 희망",
        "note": "희망 사항으로 언급되었으나 오너는 지정되지 않았다."
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토",
        "status": "오너 미지정"
      },
      {
        "item": "Hara의 생성 tarball 경로 확인",
        "status": "Minjun의 스모크 결과 게시 후 확인하기로 했으나 정확한 기한은 정해지지 않음"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로",
        "impact": "릴리스 지연 가능"
      },
      {
        "risk": "README 설치 단계가 오래됨",
        "impact": "릴리스 노트가 사용자에게 잘못된 정보를 줄 수 있음"
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "내부 수요일 스트레치 목표를 릴리스 노트에 포함해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "confirmed",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 스모크 테스트 결과를 확인한다.",
      "tarball 경로가 올바른지 확인한다.",
      "README 설치 단계가 실제 패키지와 일치하는지 점검한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 내부 수요일 스트레치 목표를 포함할지 결정한다."
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너명",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법적 승인 요구사항",
      "추가 오너",
      "추가 마감 시각"
    ]
  },
  "non_invention_rules": [
    "이 회의 기록에는 고객 또는 외부 파트너가 명시되지 않았으므로 이름을 추정하거나 추가하지 않는다.",
    "예산, 보안 사고, 프로덕션 장애, 법적 승인 요구사항은 언급되지 않았으므로 포함하지 않는다.",
    "오너가 지정되지 않은 항목은 오너를 임의 배정하지 않는다.",
    "정해지지 않은 기한은 구체적인 날짜나 시간을 만들어내지 않는다.",
    "확정된 결정, 거절된 제안, 내부 스트레치 목표, 위험, 열린 질문을 서로 섞지 않는다."
  ]
}
